typedef struct Node {
    int starting;
    int no_of_edges;
} Node;

__kernel void BFS_1(
    __global const Node *h_graph_nodes,
    __global const int *h_graph_edges,
    __global char *h_graph_mask,
    __global char *h_updating_graph_mask,
    __global const char *h_graph_visited,
    __global int *h_cost,
    const int no_of_nodes)
{
    int tid = (int)get_global_id(0);

    if (tid < no_of_nodes && h_graph_mask[tid]) {
        h_graph_mask[tid] = 0;

        int start = h_graph_nodes[tid].starting;
        int end = start + h_graph_nodes[tid].no_of_edges;
        int next_cost = h_cost[tid] + 1;

        for (int i = start; i < end; i++) {
            int id = h_graph_edges[i];
            if (!h_graph_visited[id]) {
                h_cost[id] = next_cost;
                h_updating_graph_mask[id] = 1;
            }
        }
    }
}

__kernel void BFS_2(
    __global char *h_graph_mask,
    __global char *h_updating_graph_mask,
    __global char *h_graph_visited,
    __global char *h_over,
    const int no_of_nodes)
{
    int tid = (int)get_global_id(0);

    if (tid < no_of_nodes && h_updating_graph_mask[tid]) {
        h_graph_mask[tid] = 1;
        h_graph_visited[tid] = 1;
        h_over[0] = 1;
        h_updating_graph_mask[tid] = 0;
    }
}
